#!/usr/bin/env python3
"""Batch 5 — ~250 Ink strings (Treasure Scrappers/Daydreams Wanderlust/Hot Cold/Eliisabet first intro/Bridge of the Betrayed/TUTORIAL with Jadi/start of Hilal hover)."""
import csv

T = {
    "Altyn was very pleased with my haul. He gave me enough Scrapper Badges to earn myself a Scrapper's Mask.": "Altyn era molto soddisfatto del bottino. Mi ha dato abbastanza Distintivi del Rottamatore per guadagnarmi una Maschera del Rottamatore.",
    "I can still bring any scrap metal I find to Altyn.": "Posso ancora portare ad Altyn qualsiasi rottame trovi.",

    # Daydreams of Wanderlust
    '<<"I’ve thought about it far too much, and the word that kept bubbling up was ‘space’. A great, airy expanse without walls or city smells or snakey little alleys. You know. The opposite of Eccria.">>': '<<"Ci ho pensato fin troppo, e la parola che continuava a tornarmi in mente era \'spazio\'. Una distesa ampia e arieggiata senza muri, odori di città o vicoletti tortuosi. Sai. L\'opposto di Eccria.">>',
    "Oh, I like Eccria!": "Oh, a me piace Eccria!",
    "I understand completely.": "Capisco perfettamente.",
    '<<"And I love Eccria. Always will. But I’ve had my time with it.">>': '<<"E io adoro Eccria. Sempre lo farò. Ma il mio tempo con lei è finito.">>',
    '<<"Right? Nice place to be for a while, sure, and I’ve plenty of fond memories, but…">>': '<<"Vero? Bel posto in cui stare per un po\', certo, e ho tanti bei ricordi, ma...">>',
    '<<"For now, I crave the Eastern Dunes. I want to be high up, somewhere, gazing out over the great big desert, seeing all the little pockets of life and huge stretches where there’s nothing but beetle and bone. I don’t suppose you know a place like that, do you?">>': '<<"Per ora bramo le Dune Orientali. Voglio stare in alto, da qualche parte, contemplare il grande deserto, vederne tutti i piccoli rifugi di vita e gli enormi tratti dove non c\'è altro che scarabei e ossa. Non è che conosci un posto del genere, vero?">>',
    "Excitedly, I tell Eliisabet I know the perfect spot.": "Con eccitazione, dico a Eliisabet che conosco il posto perfetto.",
    '<<"Have you found a place? No? Well, neither have I. Let me know if you do.">>': '<<"Hai trovato un posto? No? Beh, neanch\'io. Fammi sapere se ne trovi uno.">>',
    '<<"Nice to see you again, glider. Found any enticing views for me?">>': '<<"Bello rivederti, glider. Trovato qualche vista invitante per me?">>',
    "Yes! I found somewhere!": "Sì! Ho trovato un posto!",
    "Don't suggest anything.": "Non suggerire nulla.",
    '<<"Really? No, I shouldn’t say that. Of course you have, clever young glider like yourself. Tell me all about it.">>': '<<"Davvero? No, non dovrei dirlo così. Certo che l\'hai trovato, una giovane glider in gamba come te. Raccontami tutto.">>',
    "I tell Eliisabet about the view I found on the way to the Wind Tower. Her shoulders lift and in a moment, we’re making loose plans to meet there soon.": "Racconto a Eliisabet della vista trovata in cammino verso la Torre del Vento. Le sue spalle si alzano e in un attimo stiamo facendo piani approssimativi per ritrovarci là presto.",
    '<<"No luck yet? Ah, well, we’ve both plenty of time to figure it out. Let me know if you find something..">>': '<<"Ancora niente? Ah, beh, abbiamo entrambe tutto il tempo per capirlo. Fammi sapere se trovi qualcosa.">>',
    '<<"Ah! Bet you didn’t think I’d make it up here so quick, did you? Been keeping pretty spry all these years, not to mention the view’s all the motivation an old ladybird like me needs. Thank you, little glider. You’re a good one.">>': '<<"Ah! Scommetto non pensavi che sarei arrivata quassù così in fretta, eh? Mi sono mantenuta arzilla in tutti questi anni, e poi la vista è tutta la motivazione di cui una vecchia coccinella ha bisogno. Grazie, piccola glider. Sei in gamba.">>',
    '<<"I’d like to give you this, with my gratitude.">>': '<<"Vorrei darti questo, con la mia gratitudine.">>',
    "She hands me a Guards Badge and I flip it over in my hand, rubbing my thumb across its face. I thank her. ": "Mi porge un Distintivo della Guardia e lo rigiro in mano, sfregando il pollice sulla sua faccia. La ringrazio. ",
    '<<"Oh, it’s just a little token. But...suppose it’s also something to think about on your gliding, eh? The guard’s life’s treated me well enough, and if you ever fancy giving it a go, that badge gets you one step closer.>>': '<<"Oh, è solo un piccolo gesto. Ma... immagina sia anche qualcosa su cui riflettere durante il tuo volo, eh? La vita della guardia mi ha trattata abbastanza bene, e se mai dovessi voler provare, quel distintivo ti porta un passo più vicina.>>',
    "I picture myself in a Guard’s Mask. It is odd, but not absurd. Would I be any good?": "Mi immagino con la Maschera della Guardia. È strano, ma non assurdo. Sarei brava?",
    '<<Take care now, friend. Perhaps I’ll see you along my next travels. Thinking about a visit to the White Desert, you know, so if ever you happen to glide on by...">>': '<<Stammi bene, amica. Magari ci ritroviamo nei miei prossimi viaggi. Sto pensando a una visita al Wash, sai, quindi se per caso ti capita di passare di lì...">>',
    "I cheerfully promise her I will keep an eye out, and we say a warm goodbye.": "Le prometto allegramente che starò all'erta, e ci salutiamo calorosamente.",
    "Quite a view. This would be a good location to show Eliisabet. I'll keep a note to remind myself.": "Che vista. Sarebbe un bel posto da mostrare a Eliisabet. Me lo segno per ricordarmelo.",
    "I found a nice place to sit while on the way to the Wind Tower. I can see all of the Eastern Dunes from here.": "Ho trovato un bel posto in cui sedersi mentre andavo alla Torre del Vento. Da qui si vedono tutte le Dune Orientali.",
    "Daydreams Of Wanderlust": "Sogni a Occhi Aperti",
    "Eliisabet wanted to know of a place she could visit, to see the Eastern Dunes.": "Eliisabet voleva sapere di un posto da visitare per vedere le Dune Orientali.",
    "I should keep an eye out for an interesting landmark.": "Dovrei tenere d'occhio qualche punto di riferimento interessante.",
    "I've found a place that could be of interest.": "Ho trovato un posto che potrebbe essere interessante.",
    "Eliisabet should be told about this place. I think she might like it.": "Dovrei parlare di questo posto a Eliisabet. Credo le piacerà.",
    "I returned to camp and told Eliisabet about the place. She's making her way there.": "Sono tornata al campo e ho parlato a Eliisabet del posto. Si sta dirigendo lì.",
    "Maybe I could rendez-vous with Eliisabet at the place I suggested?": "Forse potrei incontrarmi con Eliisabet nel posto che ho suggerito?",
    "I met Eliisabet and she thanked me for suggesting the landmark. She seems happy.": "Ho incontrato Eliisabet e mi ha ringraziata per averle suggerito il punto. Sembra felice.",

    # Hot and Cold (Viivi)
    '<<"Young Glider! You seem young and sprightly, do you fancy a test of your speed?">>': '<<"Giovane Glider! Sembri giovane e arzilla, ti va una prova della tua velocità?">>',
    "I'm listening...": "Ti ascolto...",
    '<<"I\'ve heard there\'s a well of cool water around here. If you can take this bucket, retrieve the water, and deliver it back before it heats up completely, then I\'ll reward you handsomely.">>': '<<"Ho sentito che c\'è un pozzo di acqua fresca qui vicino. Se riesci a prendere questo secchio, a recuperare l\'acqua e a riportarmela prima che si scaldi del tutto, ti ricompenserò profumatamente.">>',
    '<<"Can\'t do it? I\'m surprised, young glider.">>': '<<"Non riesci? Mi sorprende, giovane glider.">>',
    '<<"Ah ha! You\'ve managed it! Very well done, and take your hard-earned reward!">>': '<<"Ah ah! Ce l\'hai fatta! Ben fatto, e prendi la tua ricompensa meritata!">>',
    "Hot And Cold": "Caldo e Freddo",
    "Viivi challenged me to grab some water from a nearby oasis and return it before it gets too hot.": "Viivi mi ha sfidata a prendere dell'acqua da un'oasi vicina e a riportarla prima che diventi troppo calda.",
    "I need to take the bucket, retrieve the cold water and deliver it before it gets hot.": "Devo prendere il secchio, recuperare l'acqua fredda e consegnarla prima che si scaldi.",
    "I've delivered the cold water.": "Ho consegnato l'acqua fredda.",
    "I should tell Viivi I've completed the challenge.": "Dovrei dire a Viivi di aver completato la sfida.",
    "Viivi rewarded me for completing the challenge.": "Viivi mi ha ricompensata per aver completato la sfida.",

    # Eliisabet first intro at Hercules Beetle camp
    "The guard before me stands tall, her posture shaped by duty, uniform weathered by years.": "La guardia davanti a me sta alta, la postura modellata dal dovere, l'uniforme provata dagli anni.",
    '<<"Hello there, young glider!">>': '<<"Ciao, giovane glider!">>',
    "I’m nearly startled by the force of her greeting, but her voice is comforting, somehow. Warm and welcoming.": "Sono quasi sorpresa dalla forza del suo saluto, ma la sua voce è confortante, in qualche modo. Calda e accogliente.",
    "I greet her with the accidental enthusiasm of a traveller finding a friend. She smiles behind the mask, I think.": "La saluto con l'entusiasmo accidentale di una viaggiatrice che trova un'amica. Sorride dietro la maschera, credo.",
    '<<"Always nice to meet a fellow adventurer, especially now! How are you faring so far?">>': '<<"Sempre bello incontrare un\'altra avventuriera, soprattutto adesso! Come te la stai cavando?">>',
    "The world is big and I feel very small.": "Il mondo è grande e mi sento molto piccola.",
    "I’ve never felt more free.": "Non mi sono mai sentita così libera.",
    "I need sleep.": "Ho bisogno di dormire.",
    '<<"You say that like it’s a bad thing! Isn’t it a wonder, the size of it all? That you can spend your whole life wandering, and still find more to see?">>': '<<"Lo dici come fosse una brutta cosa! Non è una meraviglia la sua grandezza? Che puoi passare l\'intera vita a vagare e trovare ancora altro da vedere?">>',
    '<<"Oh, how lovely that must be. I might normally be a little jealous, but… my circumstances are opening right up; I’m about to join you in that blissful freedom.">>': '<<"Oh, che bello dev\'essere. Normalmente sarei un po\' gelosa, ma... le mie circostanze si stanno spalancando; sto per unirmi a te in quella libertà beata.">>',
    '<<"Don’t we all! But don’t you feel lucky that you can make a bed under the stars?">>': '<<"Non ne abbiamo tutte? Ma non ti senti fortunata di poterti fare un letto sotto le stelle?">>',
    "I think about the balled-up fabric and smoothed-out rock that will make my next pillow, and many to come. My neck aches faintly at the thought of how many nights I’ll spend this way.": "Penso al tessuto appallottolato e alla roccia spianata che faranno da prossimo cuscino, e da tanti a venire. Mi duole leggermente il collo al pensiero di quante notti passerò così.",
    '<<"It’s possible I’m romanticizing it a little.">>': '<<"È possibile che lo stia un po\' romanzando.">>',
    '<<"You see, I’m getting ready to leave on my <i>second</i> gliding!">>': '<<"Vedi, mi sto preparando a partire per il mio <i>secondo</i> volo!">>',
    "She reads the confusion in my silence. Did no one tell me of the second gliding?": "Legge la confusione nel mio silenzio. Nessuno mi ha mai parlato del secondo volo?",
    '<<"I suppose it isn’t a <i>real</i> second gliding, but it’s how I’m thinking about it. A chance to see the world again, and how it’s changed.">>': '<<"Suppongo non sia un <i>vero</i> secondo volo, ma è così che lo vedo. Un\'occasione di rivedere il mondo, e come è cambiato.">>',
    '<<"I’m an Eccrine guard, you see, or-- I <i>was</i> an Eccrine guard. As of three days ago, I am officially retired.">>': '<<"Sono una guardia eccrina, vedi, o-- <i>ero</i> una guardia eccrina. Da tre giorni sono ufficialmente in pensione.">>',
    '<<"You should have seen the way the others looked at me!">>': '<<"Avresti dovuto vedere come mi guardavano gli altri!">>',
    "There is a laugh in her voice.": "C'è una risata nella sua voce.",
    '<<"All of them were so baffled to see me go, telling me how much I’d miss the big city...">>': '<<"Erano tutti così sconcertati nel vedermi andare, a dirmi quanto mi sarebbe mancata la grande città...">>',
    '<<"A few of them even felt sorry for me, like what would I do, now that my life’s purpose is complete? Can you imagine?">>': '<<"Alcuni mi compativano persino, come a dire cosa farei, ora che lo scopo della mia vita è compiuto? Te lo immagini?">>',
    "I try to, but I can barely muster a view of my purpose's start, let alone its end. I shake my head.": "Ci provo, ma a malapena riesco a immaginare l'inizio del mio scopo, figuriamoci la fine. Scuoto la testa.",
    '<<"I said \'thank you all for the strange condolences, but tomorrow marks the first time in decades that I’ll wake up in the morning and have absolutely no idea what lies ahead. And I’ve never been more excited.\'">>': '<<"Ho detto \'grazie a tutti per le strane condoglianze, ma domani sarà la prima volta in decenni che mi sveglierò la mattina senza avere la minima idea di cosa mi aspetta. E non sono mai stata così eccitata.\'">>',
    '<<"Don’t get me wrong: I’ve loved my work. I even loved the noise and the trouble of Eccria. But I’ve spent enough of my life standing around looking hard. It’s time to explore!">>': '<<"Non fraintendermi: ho amato il mio lavoro. Ho amato persino il rumore e i guai di Eccria. Ma ho passato abbastanza vita a starmene in giro con aria dura. È tempo di esplorare!">>',
    "Her glee is infectious. I ask where she’d like to go.": "La sua gioia è contagiosa. Le chiedo dove vorrebbe andare.",
    "Eliisabet greets me.": "Eliisabet mi saluta.",

    # A View From The Bridge
    '<<"I\'m heading to the Badlands, I think. I want to see the Bridge of the Betrayed!">>': '<<"Sto andando ai Badlands, credo. Voglio vedere il Ponte dei Traditi!">>',
    '<<"If you haven’t already, you should definitely go and see it yourself. You’ll want the northern Badlands, south-west of here.">>': '<<"Se non l\'hai già fatto, dovresti assolutamente andare a vederlo. Vuoi i Badlands settentrionali, a sud-ovest di qui.">>',
    "I nod, trying to keep the directions in mind, and Eliisabet gives me a little tap.": "Annuisco, cercando di tenere a mente le indicazioni, ed Eliisabet mi dà un colpetto.",
    '<<"Maybe I\'ll see you up there.">>': '<<"Forse ci vediamo lassù.">>',
    '<<"Ah! You decided to join me!">>': '<<"Ah! Hai deciso di raggiungermi!">>',
    "I wanted to see you!": "Volevo vederti!",
    "I wanted to see the view!": "Volevo vedere il panorama!",
    "I forgot you’d be here!": "Mi ero dimenticata che saresti stata qui!",
    "I tell Eliisabet that I wanted to see her again, and so here I am for our second hello. She seems to like that and gives me a little pat on the arm.": "Dico a Eliisabet che volevo rivederla, ed eccomi qui per il nostro secondo saluto. Sembra apprezzarlo e mi dà un colpetto sul braccio.",
    '<<"I wanted to see you too! Didn’t have any trouble with the climb, did you?">>': '<<"Anch\'io volevo vederti! Non hai avuto problemi con la scalata, vero?">>',
    '<<"You’ve got good taste, then, and I’ve got good news! Because even though I’ve been standing up here taking it all in, there’s still plenty of view left for you.">>': '<<"Allora hai buon gusto, e io ho una buona notizia! Anche se sono stata quassù ad assorbirla, c\'è ancora un sacco di vista per te.">>',
    "I laugh a little and she pats my arm.": "Rido un po' e mi dà un colpetto sul braccio.",
    '<<"I hope you didn’t have any trouble with the climb?">>': '<<"Spero tu non abbia avuto problemi con la scalata?">>',
    "Eliisabet cackles and pats me on the shoulder.": "Eliisabet ride forte e mi dà una pacca sulla spalla.",
    '<<"Isn’t it funny; bad memories make for good coincidences. I hope you didn’t have any trouble with the climb?">>': '<<"Buffo, no? I cattivi ricordi fanno belle coincidenze. Spero tu non abbia avuto problemi con la scalata?">>',
    "I tell her no, and ask how she managed.": "Le dico di no, e le chiedo come ha fatto lei.",
    '<<"Been keeping pretty spry all these years, not to mention the view’s all the motivation an old ladybird like me needs. Thank you, though, little glider. You’re a good one.">>': '<<"Mi sono mantenuta arzilla in tutti questi anni, e poi la vista è tutta la motivazione di cui una vecchia coccinella ha bisogno. Grazie comunque, piccola glider. Sei in gamba.">>',
    '<<"I’d like to give you this, with my gratitude. Given our present location, it does seem a little on-the-nose, perhaps, but...">>': '<<"Vorrei darti questo, con la mia gratitudine. Data la nostra posizione attuale, forse sembra un po\' troppo a tema, ma...">>',
    "With a quick nod to the great statues looming behind her, Eliisabet hands me a Guards Badge. I flip it over in my hand, rubbing my thumb across its face, and I thank her for it.": "Con un rapido cenno alle grandi statue che incombono dietro di lei, Eliisabet mi porge un Distintivo della Guardia. Lo rigiro in mano, sfregando il pollice sulla faccia, e la ringrazio.",
    '<<"Oh, it’s just a little token. But... suppose it’s also something to think about on your gliding, eh?">>': '<<"Oh, è solo un piccolo gesto. Ma... immagina sia anche qualcosa su cui pensare durante il tuo volo, eh?">>',
    '<<"The guard’s life’s treated me well enough, and if you ever fancy giving it a go, that badge gets you one step closer.">>': '<<"La vita della guardia mi ha trattato abbastanza bene, e se mai dovessi voler provare, quel distintivo ti porta un passo più vicina.">>',
    '<<"Take care now, friend. Perhaps I’ll see you along my next travels. Thinking about a visit to the Wash, you know, so if ever you happen to glide on by...">>': '<<"Stammi bene, amica. Magari ci ritroviamo nei miei prossimi viaggi. Sto pensando a una visita al Wash, sai, quindi se per caso ti capita di passare di lì...">>',
    "I cheerfully promise her I will keep an eye out.": "Le prometto allegramente che starò all'erta.",
    '<<"One more thing. If you do go the Guard route?">>': '<<"Un\'ultima cosa. Se prendi davvero la strada della Guardia?">>',
    "I perk up. She turns and gestures to the statues again.": "Mi rianimo. Si volta e indica di nuovo le statue.",
    '<<"Aim to be the one with the high ground. Way he’s angled, the fellow coming up from the bottom doesn’t stand a chance.">>': '<<"Punta a essere quella in alto. Per come è angolato, il tipo che arriva dal basso non ha scampo.">>',
    "We share a warm goodbye and I go on my way.": "Ci salutiamo calorosamente e me ne vado.",
    '<<"I\'ll see you round.">>': '<<"Ci si vede.">>',
    "A View from the Bridge": "Una Vista dal Ponte",
    "I met Eliisabet, a retired Eccrine Guard, at Burnt Oak Station. She said she was heading to the Bridge of the Betrayed, and suggested I should go and see it myself.": "Ho incontrato Eliisabet, una guardia eccrina in pensione, alla Burnt Oak Station. Ha detto che era diretta al Ponte dei Traditi, e ha suggerito che lo vedessi anch'io.",
    "I should go and find Eliisabet at the Bridge of the Betrayed. It's south-west of Burnt Oak Station, in the northern Badlands.": "Dovrei andare a trovare Eliisabet al Ponte dei Traditi. È a sud-ovest della Burnt Oak Station, nei Badlands settentrionali.",
    "I climbed up to the bridge and met Eliisabet there.": "Sono salita al ponte e ho incontrato Eliisabet lì.",

    # Tutorial / Jadi (THE OPENING — what the user is stuck on!)
    "I can feel Jadi smiling behind her mask, just as I know she can feel the teeth-baring little grimace behind mine.": "Sento Jadi sorridere dietro la sua maschera, proprio come so che lei sente la mia smorfietta a denti scoperti dietro la mia.",
    "I’m nervous, and she’s softly, sweetly amused. In her eyes, I probably have very little to worry about.": "Sono nervosa, e lei è dolcemente, soavemente divertita. Ai suoi occhi, probabilmente non ho granché di cui preoccuparmi.",
    '<<"You know you have nothing to worry about, don’t you, Sable?">>': '<<"Lo sai che non hai nulla di cui preoccuparti, vero, Sable?">>',
    "And yet...": "Eppure...",
    "I know, I know...": "Lo so, lo so...",
    "I’m not worried!": "Non sono preoccupata!",
    "I shrug, but any attempts to act casual are fruitless. The movement is jerky, and I don’t think I’ve ever been more aware of my little shoulders. She laughs.": "Faccio spallucce, ma ogni tentativo di sembrare disinvolta è inutile. Il movimento è scattoso, e credo di non essere mai stata così consapevole delle mie spalline. Lei ride.",
    '<<"I mean it!">>': '<<"Dico sul serio!">>',
    "I tell Jadi that I know, but that it hasn’t quite sunk in yet. She chuckles.": "Dico a Jadi che lo so, ma che non l'ho ancora del tutto realizzato. Ridacchia.",
    '<<"I promise you, Sable! You’re fine.">>': '<<"Te lo prometto, Sable! Stai bene.">>',
    "I tell her I’m not worried at all, and it’s possibly the least convincing I’ve ever been.": "Le dico che non sono preoccupata per niente, ed è probabilmente la cosa meno convincente che abbia mai detto.",
    '<<"You can say that, my love...">>': '<<"Puoi dirlo, amore mio...">>',
    '<<"But I do know how you are. You’re going to be nervous until you’ve started, and then you’ll act like you’ve been doing it your whole life.">>': '<<"Ma so come sei. Sarai nervosa finché non avrai iniziato, e poi farai come se l\'avessi fatto per tutta la vita.">>',
    '<<"Remember the first time you rode a bike?">>': '<<"Ricordi la prima volta che hai guidato una hoverbike?">>',
    '<<"You wouldn’t even let me put you on the seat, you were so afraid. Your hands were like little claws gripping onto me...">>': '<<"Non mi lasciavi neanche metterti sul sellino, avevi così paura. Le tue mani erano come piccoli artigli aggrappati a me...">>',
    "I feel the memory in my fingers.": "Sento il ricordo nelle dita.",
    '<<"But then I promised you it was going to be all right. I told you how much I had loved riding my bike as a young woman, and how wonderful the wind felt through fabric...">>': '<<"Ma poi ti ho promesso che sarebbe andato tutto bene. Ti ho detto quanto avevo amato cavalcare la mia hoverbike da giovane, e quanto fosse meraviglioso il vento sul tessuto...">>',
    '<<"Suddenly, there you were. You sat down. You leaned forward and put those little grasping claws on the handles and you were off.">>': '<<"All\'improvviso, eccoti lì. Ti sei seduta. Ti sei sporta in avanti, hai messo quegli artigliucci sui manubri ed eri partita.">>',
    '<<"And I remember thinking, just... watching you tear over the sand...">>': '<<"E ricordo di aver pensato, solo... guardandoti sfrecciare sulla sabbia...">>',
    '<<"Look at her. She can do whatever she wants.">>': '<<"Guardala. Può fare tutto ciò che vuole.">>',
    "Jadi reaches out and places a hand on the edge of my mask.": "Jadi allunga la mano e la posa sul bordo della mia maschera.",
    '<<"And you can, Sable.">>': '<<"E puoi farlo, Sable.">>',
    "I take a breath.": "Prendo fiato.",
    "I think I’m ready.": "Credo di essere pronta.",
    "I don’t know where to start.": "Non so da dove cominciare.",
    "I changed my mind. I’m staying.": "Ho cambiato idea. Resto.",
    "I thank Jadi for the encouragement, and tell her with a nod that I think I’m ready.": "Ringrazio Jadi per l'incoraggiamento, e con un cenno le dico che credo di essere pronta.",
    '<<"I know you are. So let’s get you started.">>': '<<"Lo so. Allora facciamoti partire.">>',
    "Jadi’s story warms me, but I feel too overwhelmed to let it settle. I tell her with a sigh that I don’t know where to begin. She chuckles.": "La storia di Jadi mi scalda, ma mi sento troppo sopraffatta per lasciarla sedimentare. Con un sospiro le dico che non so da dove cominciare. Lei ridacchia.",
    '<<"Well, I can help with that.">>': '<<"Beh, su quello posso aiutarti.">>',
    "Well, it was a worthy effort. I tell Jadi that I appreciate the lesson, but that her story has made me nostalgic and now I would very much like to remain here, in the safety of our home. She laughs.": "Beh, è stato un tentativo nobile. Dico a Jadi che apprezzo la lezione, ma che la sua storia mi ha resa nostalgica e ora vorrei tantissimo rimanere qui, al sicuro a casa nostra. Lei ride.",
    '<<"Come on! You’re running late.">>': '<<"Dai! Sei in ritardo.">>',
    "I concede with a sigh just loud enough for her to hear.": "Cedo con un sospiro abbastanza rumoroso perché lo senta.",
    '<<"You’ll need to talk to Hilal and Driss. Driss should already have made the arrangements for your bike, and Hilal will share something... well, let’s say as useful as it is fun, hm?">>': '<<"Dovrai parlare con Hilal e Driss. Driss dovrebbe aver già preparato la tua hoverbike, e Hilal condividerà qualcosa... beh, diciamo tanto utile quanto divertente, mh?">>',
    "I think I might suspect what Jadi’s saying, but I stay quiet.": "Credo di sospettare cosa intende Jadi, ma sto zitta.",
    '<<"After that, I suppose we’ll see you off.">>': '<<"Dopodiché, immagino ti accompagneremo alla partenza.">>',
    "I’ll be back soon.": "Tornerò presto.",
    "What if I choose the wrong path?": "E se scegliessi la strada sbagliata?",
    "I tell Jadi I’ll be back soon.": "Dico a Jadi che tornerò presto.",
    '<<"Sable, don’t go planning your return before you’ve even left. Take all the time you need. It’s a big decision you’re making out there.">>': '<<"Sable, non programmare il ritorno prima ancora di partire. Prenditi tutto il tempo che ti serve. È una grande decisione quella che farai là fuori.">>',
    "I tell her that’s why I’m so eager to make it. To choose well and quickly, so that I don’t go too far down the wrong path.": "Le dico che è proprio per questo che ho tanta fretta di prenderla. Per scegliere bene e in fretta, e non spingermi troppo lontano sulla strada sbagliata.",
    "I ask Jadi what will become of me if I choose the wrong path.": "Chiedo a Jadi cosa ne sarà di me se scelgo la strada sbagliata.",
    '<<"There are no wrong paths, Sable. Or right ones. I’ll be glad if you choose to stay with the Ibexii, but... truth be told, I’ll be glad no matter what. So long as you’re happy.">>': '<<"Non ci sono strade sbagliate, Sable. Né giuste. Sarò felice se sceglierai di restare con gli Ibexii, ma... a dirla tutta, sarò felice in ogni caso. Purché tu sia felice.">>',
    '<<"Whatever you decide, you do so with my blessing. So don’t try using me as an excuse to come home early, eh?">>': '<<"Qualunque cosa tu decida, lo fai con la mia benedizione. Quindi non provare a usarmi come scusa per tornare a casa in anticipo, eh?">>',
    "She knows me.": "Mi conosce.",
    '<<"Now go speak with Hilal. I’ll be there to see you off.">>': '<<"Ora vai a parlare con Hilal. Sarò lì alla partenza.">>',
    '<<"And speak to Driss, as well! I’ve told him to arrange your bike with Sizo but you know how he is.">>': '<<"E parla anche con Driss! Gli ho detto di preparare la tua hoverbike con Sizo, ma sai com\'è fatto.">>',
    '<<"I have something to give you. A compass to help you on your journey. It\'s the same one  I used on my Gliding, an artefact you might say.">>': '<<"Ho qualcosa da darti. Una bussola per aiutarti nel viaggio. È la stessa che usavo io durante il mio Volo, un cimelio si potrebbe dire.">>',
    "I take the device in my palm. It fits naturally there, perfectly weighted and crafted. Each component slides together with incredible, satisfying precision.": "Prendo il dispositivo nel palmo. Vi calza naturalmente, perfettamente bilanciato e lavorato. Ogni componente si incastra con una precisione incredibile, soddisfacente.",
    "Thank you.": "Grazie.",
    '<<"Go on, go on. It\'s nearly time!">>': '<<"Vai, vai. È quasi ora!">>',
    "I return to Jadi with a new lightness...": "Torno da Jadi con una nuova leggerezza...",
    "...And it makes the weight of my departure feel heavier still. What a strange day.": "...E rende il peso della mia partenza ancora più pesante. Che strana giornata.",
    '<<"Sable! Is that a badge you’ve got there?">>': '<<"Sable! Quello che hai è un distintivo?">>',
    "Sizo gave it to me!": "Me l'ha dato Sizo!",
    "Look at me, Jadi! I’m already Gliding!": "Guardami, Jadi! Sto già volando!",
    "I tell Jadi that Sizo gave me the badge.": "Dico a Jadi che Sizo mi ha dato il distintivo.",
    '<<"Then you must have earned it. Well done.">>': '<<"Allora deve essertelo meritato. Ben fatto.">>',
    "I take up the badge and hold it out for closer examination. So close, in fact, that Jadi chuckles and has to take a small step back.": "Prendo il distintivo e lo offro al suo esame ravvicinato. Così vicino che Jadi ridacchia e deve fare un piccolo passo indietro.",
    '<<"Sizo must have really felt you earned it. Well done.">>': '<<"Sizo dev\'essere convinto che te lo sei meritato. Ben fatto.">>',
    "I give a bow of thanks.": "Faccio un inchino di ringraziamento.",
    '<<"Well, Sable! If you keep this up, you’ll be headed for the Mask Caster in no time!">>': '<<"Bene, Sable! Se continui così, sarai dal Forgiatore di Maschere in un batter d\'occhio!">>',
    "I try to think about going to a Mask Caster, but it seems impossibly far away. Imagine <i>choosing what I want to be</i>?": "Provo a pensare di andare da un Forgiatore di Maschere, ma sembra incredibilmente lontano. Immagina <i>scegliere chi voglio essere</i>?",
    "Imagine choosing what I want to be....<i>forever</i>?!": "Immagina scegliere chi voglio essere... <i>per sempre</i>?!",
    '<<"I know what you’re thinking, but don’t worry about it. You’ll get plenty of badges when you’re out there, and once you’ve got three alike, you can trade it in for that mask.">>': '<<"So a cosa pensi, ma non preoccuparti. Otterrai un sacco di distintivi là fuori, e quando ne avrai tre uguali, potrai scambiarli per la maschera corrispondente.">>',
    '<<"But don’t feel like your first mask is your final choice. The Gliding is about freedom, and exploration. I suggest you claim as many masks as you wish!">>': '<<"Ma non pensare che la tua prima maschera sia la scelta definitiva. Il Volo riguarda la libertà e l\'esplorazione. Ti consiglio di prendere tutte le maschere che vuoi!">>',
    '<<"Only at your final ceremony will you be asked to choose one.">>': '<<"Solo alla cerimonia finale ti sarà chiesto di sceglierne una.">>',
    "How will I choose one?": "Come la sceglierò?",
    "Which one should I choose?": "Quale dovrei scegliere?",
    '<<"You’ll have to feel it out. But when you know, you’ll know.">>': '<<"Dovrai sentirla. Ma quando lo saprai, lo saprai.">>',
    '<<"Now.">>': '<<"Ora.">>',
    'The tone of her "now" puts the butterflies back in my stomach. With all of this done, there is only one thing left.': "Il tono del suo \"ora\" rimette le farfalle nel mio stomaco. Fatto tutto questo, resta una sola cosa.",
    '<<"It’s time, then, isn’t it? Time to walk through the Face Door at the Temple of Rohana...">>': '<<"È il momento, no? Il momento di varcare la Porta dei Volti al Tempio di Rohana...">>',
    '<<"There, you’ll assemble your Gliding mask...">>': '<<"Lì assemblerai la tua maschera del Volo...">>',
    '<<"...and go.">>': '<<"...e andrai.">>',
    "There are things I wish to convey to Jadi here, depths of love and gratitude and fear and worry and hope. And though I find myself unable to speak any of it in words, I know she understands.": "Ci sono cose che vorrei comunicare a Jadi qui, profondità di amore e gratitudine e paura e preoccupazione e speranza. E anche se mi ritrovo incapace di esprimerne nessuna a parole, so che lei capisce.",
    '<<"Before you leave, child.">>': '<<"Prima che tu parta, bambina mia.">>',
    '<<"I made you these. They are dyed with the traditional Ibexii maroon, and I hope provide you great comfort out in the desert.">>': '<<"Ti ho fatto questi. Sono tinti del tradizionale rosso scuro Ibexii, e spero ti diano grande conforto nel deserto.">>',
    '<<"When you leave today, you will no longer be Sable, clan-child of the Ibexii. You will simply be Sable, and the rest will come.">>': '<<"Quando partirai oggi, non sarai più Sable, figlia del clan degli Ibexii. Sarai semplicemente Sable, e il resto verrà.">>',
    '<<"But no matter what you are, no matter where your journey takes you, I will always know you. I will always love you.">>': '<<"Ma qualunque cosa tu sia, ovunque ti porti il viaggio, ti riconoscerò sempre. Ti amerò sempre.">>',
    '<<"And I will see you again.">>': '<<"E ti rivedrò.">>',
    "I don’t know where my journey will end, but I know where it must begin.": "Non so dove finirà il mio viaggio, ma so dove deve iniziare.",
    "And I am ready.": "E sono pronta.",
    "Jadi's voice echoes strangely through the machine, yet still it warms me.": "La voce di Jadi echeggia stranamente attraverso la macchina, ma mi scalda lo stesso.",
    '<<"Well, Sable... this is it.">>': '<<"Bene, Sable... ci siamo.">>',
    '<<"By the time you hear this, we will have gone. The Gliding is a journey that must begin alone.">>': '<<"Quando sentirai questo messaggio, saremo già partiti. Il Volo è un viaggio che deve iniziare da soli.">>',
    "There is a certain nuance lost in transmission, and for that I am grateful. It would be far too much to hear the cracks in her voice and not run weepily into her arms to stay forever.": "C'è una certa sfumatura che si perde nella trasmissione, e per questo sono grata. Sarebbe troppo sentire le incrinature nella sua voce e non correre piangendo tra le sue braccia per restare per sempre.",
    "But I am ready. And so I close my eyes and listen.": "Ma sono pronta. E così chiudo gli occhi e ascolto.",
    '<<"But though you go by yourself, you are not without friends. You are not without family. You are not without love. These things you will always carry with you, as you do your mask.">>': '<<"Ma anche se vai da sola, non sei senza amici. Non sei senza famiglia. Non sei senza amore. Queste cose le porterai sempre con te, come fai con la tua maschera.">>',
    "<<And I know I’m not supposed to do this... but if I were you, I might go and see Utarii. They're the Machinist at Burnt Oak Station, and among Sizo’s closest friends.\">>": "<<E so che non dovrei fare così... ma se fossi in te, andrei a trovare Utarii. È la Macchinista alla Burnt Oak Station, e tra gli amici più cari di Sizo.>>",
    '<<"Utarii’s a good contact to have on one’s Gliding, and a fine way to get another Machinist badge if you’re so inclined. Only a suggestion, though.">>': '<<"Utarii è un buon contatto da avere durante il Volo, e un buon modo per ottenere un altro distintivo del Macchinista se ti va. È solo un suggerimento, però.">>',
    '<<"As for us, I’ll send another message once we’ve returned to the Ewer, so keep an eye on the postboxes. And try not to forget us.">>': '<<"Quanto a noi, ti manderò un altro messaggio quando saremo tornati all\'Ewer, quindi tieni d\'occhio le cassette postali. E cerca di non dimenticarci.">>',
    "She takes a long breath and I forget that things as easy as breathing could ever exist.": "Prende un lungo respiro e dimentico che cose facili come respirare possano esistere.",
    '<<"The world is waiting, Sable.">>': '<<"Il mondo ti aspetta, Sable.">>',
    '<<"Good luck.">>': '<<"Buona fortuna.">>',
    "The Ceremony": "La Cerimonia",
    "I should head back to camp.": "Dovrei tornare al campo.",
    "I spoke to Jadi at camp. She said Hilal and Driss had tasks for me to complete.": "Ho parlato con Jadi al campo. Ha detto che Hilal e Driss hanno dei compiti per me.",
    "I need to complete tasks for Hilal and Driss.": "Devo completare i compiti di Hilal e Driss.",
    "I completed Driss and Hilal's tasks.": "Ho completato i compiti di Driss e Hilal.",
    "Sizo has a task for me.": "Sizo ha un compito per me.",
    "I completed Sizo's task.": "Ho completato il compito di Sizo.",
    "I should speak to Jadi about the final Gliding ceremony.": "Dovrei parlare con Jadi della cerimonia finale del Volo.",
    "Jadi told me to head back to the Temple of Rohana to start my Gliding.": "Jadi mi ha detto di tornare al Tempio di Rohana per iniziare il mio Volo.",
    "I should head to the temple to begin my Gliding.": "Dovrei andare al tempio per iniziare il mio Volo.",
    "I completed the ceremony and received my Ibex mask.": "Ho completato la cerimonia e ricevuto la mia maschera Ibex.",
    "Return to camp.": "Torna al campo.",
    "When I returned to camp, the clan had packed up and left without me.": "Quando sono tornata al campo, il clan aveva impacchettato tutto ed era partito senza di me.",
    "Leave the canyon.": "Lascia il canyon.",
    "I left the canyon and began my Gliding.": "Ho lasciato il canyon e ho iniziato il mio Volo.",
    "I should speak to Utarii, the Machinist at Burnt Oak Station.": "Dovrei parlare con Utarii, la Macchinista alla Burnt Oak Station.",
    "I made it to Burnt Oak Station, and spoke with Utarii.": "Sono arrivata alla Burnt Oak Station e ho parlato con Utarii.",
    "Slicing Sands": "Sabbie Taglienti",
    "Ride the sandcutter. It's definitely not a test.": "Cavalca la sandcutter. Non è assolutamente una prova.",
    "Ride the sandcutter through the Ring and back.": "Cavalca la sandcutter attraverso l'Anello e ritorno.",
    "I rode a hoverbike for the first time and didn't catch on fire.": "Ho cavalcato una hoverbike per la prima volta e non ho preso fuoco.",
    "I should speak to Driss.": "Dovrei parlare con Driss.",
    "Driss gave me the sandcutter to drive.": "Driss mi ha dato la sandcutter da guidare.",

    # Hilal hover start
    "As I approach Hilal, they give an enthusiastic wave. I’ve always appreciated Hilal’s verve and vigor, and on a day like this, I’m ready to match it-- with a touch of nerves for balance.": "Mentre mi avvicino a Hilal, mi saluta con entusiasmo. Ho sempre apprezzato la verve e il vigore di Hilal, e in un giorno come questo, sono pronta a metterli alla pari — con un tocco di nervosismo per bilanciare.",
    '<<"Sable! Take this.">>': '<<"Sable! Prendi questa.">>',
    "Hilal hands me a small, round stone. As it nestles into my palm, I feel a warmth not borrowed from Hilal’s hands, but emanating from within. I run my thumb over it and find it softly electric, like static on cloth.": "Hilal mi porge una piccola pietra rotonda. Mentre si annida nel mio palmo, sento un calore che non viene dalle mani di Hilal, ma emana dall'interno. Ci passo sopra il pollice e la trovo lievemente elettrica, come la statica sul tessuto.",
    "What is this?": "Cos'è?",
    "Thank you!": "Grazie!",
    "I didn’t bring anything for <i>you</i>!": "Non ho portato nulla per <i>te</i>!",
    "I try to sound less confused than I am, but ask Hilal what this is.": "Cerco di sembrare meno confusa di quanto sia, e chiedo a Hilal cos'è.",
    '<<"Oh, Sable, you can’t leave without it!">>': '<<"Oh, Sable, non puoi partire senza!">>',
    "I thank them for the fuzzy rock.": "Lo ringrazio per la pietruzza vellutata.",
}

def main():
    csv_in = 'translations/ink_strings.csv'
    rows = list(csv.DictReader(open(csv_in)))
    applied = 0
    for r in rows:
        if r['en'] in T and not r['it']:
            r['it'] = T[r['en']]
            applied += 1
    with open(csv_in, 'w', newline='', encoding='utf-8') as f:
        w = csv.DictWriter(f, fieldnames=['path', 'en', 'it'], quoting=csv.QUOTE_ALL)
        w.writeheader()
        w.writerows(rows)
    total_translated = sum(1 for r in rows if r['it'])
    print(f"Applied {applied} new translations from this batch")
    print(f"Total translated: {total_translated}/{len(rows)}")

if __name__ == '__main__':
    main()
